"use client";

import { useQuery } from "@tanstack/react-query";
import { History, FileText, Download, Eye, MapPin, Clock } from "lucide-react";
import { cn } from "@/lib/utils";

type AccessLog = {
  id: string; queueCode: string; accessType: string;
  ipAddress: string | null; accessedAt: string; filePath: string | null;
};

const TYPE_META: Record<string, { label: string; icon: typeof Eye; color: string }> = {
  LAB_PDF:  { label: "Downloaded PDF",    icon: Download, color: "text-violet-500 bg-violet-50 dark:bg-violet-500/10 border-violet-200 dark:border-violet-500/20" },
  VITALS:   { label: "Viewed Vitals",     icon: Eye,      color: "text-blue-500 bg-blue-50 dark:bg-blue-500/10 border-blue-200 dark:border-blue-500/20" },
  RECEIPT:  { label: "Viewed Receipt",    icon: FileText, color: "text-amber-500 bg-amber-50 dark:bg-amber-500/10 border-amber-200 dark:border-amber-500/20" },
  SUMMARY:  { label: "Viewed Summary",    icon: Eye,      color: "text-green-500 bg-green-50 dark:bg-green-500/10 border-green-200 dark:border-green-500/20" },
};

function formatDateTime(d: string) {
  return new Date(d).toLocaleString("en-US", {
    month: "short", day: "numeric", year: "numeric",
    hour: "numeric", minute: "2-digit",
  });
}

function groupByDate(logs: AccessLog[]) {
  const groups: Record<string, AccessLog[]> = {};
  for (const log of logs) {
    const key = new Date(log.accessedAt).toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" });
    if (!groups[key]) groups[key] = [];
    groups[key].push(log);
  }
  return groups;
}

export default function AccessHistoryPage() {
  const { data, isLoading } = useQuery<{ data: AccessLog[] }>({
    queryKey: ["access-history"],
    queryFn: () => fetch("/api/access-history").then((r) => r.json()),
    staleTime: 60_000,
  });

  const logs = data?.data ?? [];
  const grouped = groupByDate(logs);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <div className="flex items-center gap-2 mb-1">
          <div className="flex h-8 w-8 items-center justify-center rounded-xl bg-primary/10 border border-primary/20">
            <History className="h-4 w-4 text-primary" />
          </div>
          <span className="text-xs font-semibold text-primary tracking-widest uppercase">Security</span>
        </div>
        <h1 className="text-2xl font-bold text-foreground">Access History</h1>
        <p className="text-sm text-muted-foreground mt-0.5">A record of every time you accessed your results</p>
      </div>

      {/* Info banner */}
      <div className="flex items-start gap-3 rounded-2xl border border-border bg-muted/30 px-4 py-3.5">
        <Clock className="h-4 w-4 text-muted-foreground/60 shrink-0 mt-0.5" />
        <p className="text-xs text-muted-foreground leading-relaxed">
          This log shows the last 100 accesses to your records. If you notice any suspicious activity,
          contact our support team immediately.
        </p>
      </div>

      {/* Timeline */}
      {isLoading ? (
        <div className="space-y-6">
          {[0, 1, 2].map((g) => (
            <div key={g} className="space-y-3">
              <div className="h-4 w-32 rounded bg-muted animate-pulse" />
              {[0, 1, 2].map((i) => (
                <div key={i} className="flex gap-4 animate-pulse">
                  <div className="h-9 w-9 rounded-xl bg-muted shrink-0" />
                  <div className="flex-1 space-y-2 py-1">
                    <div className="h-3.5 w-48 rounded bg-muted" />
                    <div className="h-3 w-32 rounded bg-muted" />
                  </div>
                </div>
              ))}
            </div>
          ))}
        </div>
      ) : logs.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 gap-3">
          <div className="flex h-16 w-16 items-center justify-center rounded-2xl bg-muted">
            <History className="h-8 w-8 text-muted-foreground/30" />
          </div>
          <p className="text-sm text-muted-foreground">No access history yet</p>
          <p className="text-xs text-muted-foreground">Your record views and downloads will appear here</p>
        </div>
      ) : (
        <div className="space-y-8">
          {Object.entries(grouped).map(([date, dayLogs]) => (
            <div key={date}>
              <p className="text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-4">{date}</p>
              <div className="relative">
                {/* Timeline line */}
                <div className="absolute left-4 top-0 bottom-0 w-px bg-border" />
                <div className="space-y-4">
                  {dayLogs.map((log) => {
                    const meta = TYPE_META[log.accessType] ?? TYPE_META.SUMMARY;
                    const Icon = meta.icon;
                    return (
                      <div key={log.id} className="flex gap-4 relative">
                        {/* Icon */}
                        <div className={cn(
                          "flex h-9 w-9 shrink-0 items-center justify-center rounded-xl border z-10",
                          meta.color
                        )}>
                          <Icon className="h-4 w-4" />
                        </div>
                        {/* Content */}
                        <div className="flex-1 min-w-0 rounded-2xl bg-card border border-border px-4 py-3">
                          <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-1 sm:gap-3">
                            <div className="min-w-0">
                              <p className="text-sm font-semibold text-foreground">{meta.label}</p>
                              <p className="text-xs text-muted-foreground mt-0.5 font-mono truncate">
                                Visit #{log.queueCode}
                              </p>
                            </div>
                            <div className="flex flex-col gap-0.5 sm:items-end shrink-0">
                              <p className="text-xs text-muted-foreground flex items-center gap-1">
                                <Clock className="h-3 w-3 shrink-0" />
                                {formatDateTime(log.accessedAt)}
                              </p>
                              {log.ipAddress && (
                                <p className="text-[10px] text-muted-foreground/60 flex items-center gap-1">
                                  <MapPin className="h-2.5 w-2.5 shrink-0" /> {log.ipAddress}
                                </p>
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
